"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[211],{2028:e=>{e.exports=JSON.parse('{"functions":[{"name":"new","desc":"Creates a new, independent adaptive object pool.\\n\\n`Factory` and `Reset` are required. All other config fields are optional\\nand fall back to sensible defaults.\\n\\n```lua\\nlocal Pool = Fluix.new({\\n    Factory  = function() return Part.new() end,\\n    Reset    = function(p) p.Parent = nil end,\\n    MinSize  = 16,\\n    Headroom = 3.0,\\n})\\n```","params":[{"name":"config","desc":"Pool configuration table.","lua_type":"PoolerConfig"}],"returns":[{"desc":"A new pool instance.","lua_type":"Pooler"}],"function_type":"static","source":{"line":79,"path":"docs/Fluix.lua"}},{"name":"Seed","desc":"Pre-allocates `n` objects into the pool. Drains the hot sub-pool first,\\nthen fills cold up to `MaxSize`. Safe to call before gameplay starts.\\n\\n```lua\\nPool:Seed(32)  -- warm up 32 objects before the round begins\\n```","params":[{"name":"n","desc":"Number of objects to pre-allocate.","lua_type":"number"}],"returns":[],"function_type":"method","source":{"line":124,"path":"docs/Fluix.lua"}},{"name":"Acquire","desc":"Acquires an object from the pool. Drains the hot sub-pool first, then cold.\\nOn a miss, Fluix tries `BorrowPeers` in order before calling `Factory`.\\n\\nAn optional `Apply` function is called on the object before it is returned,\\nallowing inline initialisation without a separate step.\\n\\n```lua\\n-- Without inline init\\nlocal bullet = Pool:Acquire()\\nbullet.Position = spawnPos\\n\\n-- With inline init (preferred on hot paths)\\nlocal bullet = Pool:Acquire(function(b)\\n    b.Position = spawnPos\\n    b.Velocity = direction * speed\\nend)\\n```","params":[{"name":"Apply","desc":"Optional initialiser called before returning.","lua_type":"((obj: T) -> ())?"}],"returns":[{"desc":"The acquired object.","lua_type":"T"}],"function_type":"method","source":{"line":151,"path":"docs/Fluix.lua"}},{"name":"Release","desc":"Returns an object to the pool. `Reset` is called on the object. If the pool\\nis full, `OnOverflow` is called instead (or the object is dropped if\\n`OnOverflow` is not set).\\n\\nDouble-release is detected and a warning is emitted.\\n\\n```lua\\nPool:Release(bullet)\\n```","params":[{"name":"obj","desc":"The object to return.","lua_type":"T"}],"returns":[],"function_type":"method","source":{"line":169,"path":"docs/Fluix.lua"}},{"name":"ReleaseAll","desc":"Force-returns every currently live object at once. `Reset` is called on\\neach object. Useful for wave clears or round resets.\\n\\n```lua\\nPool:ReleaseAll()\\n```","params":[],"returns":[],"function_type":"method","source":{"line":182,"path":"docs/Fluix.lua"}},{"name":"RegisterPeer","desc":"Adds a sibling pool to the borrow list. On a factory miss, Fluix will\\nattempt to pop an object from each registered peer\'s cold pool in order.\\n\\n```lua\\nBulletPool:RegisterPeer(FragPool)\\nFragPool:RegisterPeer(BulletPool)\\n```","params":[{"name":"peer","desc":"The sibling pool to register.","lua_type":"Pooler"}],"returns":[],"function_type":"method","source":{"line":200,"path":"docs/Fluix.lua"}},{"name":"UnregisterPeer","desc":"Removes a sibling pool from the borrow list.\\n\\n```lua\\nBulletPool:UnregisterPeer(FragPool)\\n```","params":[{"name":"peer","desc":"The sibling pool to remove.","lua_type":"Pooler"}],"returns":[],"function_type":"method","source":{"line":214,"path":"docs/Fluix.lua"}},{"name":"Pause","desc":"Disconnects the Heartbeat without clearing any pool state. Pre-warming,\\nadaptive sizing, and TTL checks stop until `Resume` is called. Useful during\\ncutscenes or loading screens.\\n\\n```lua\\nPool:Pause()\\n```","params":[],"returns":[],"function_type":"method","source":{"line":230,"path":"docs/Fluix.lua"}},{"name":"Resume","desc":"Reconnects the Heartbeat. Safe to call if already active.\\n\\n```lua\\nPool:Resume()\\n```","params":[],"returns":[],"function_type":"method","source":{"line":242,"path":"docs/Fluix.lua"}},{"name":"Drain","desc":"Evicts all pooled objects from the hot and cold tiers, calling `OnOverflow`\\n(or discarding) each one. Does not touch live objects or reset the EMA.\\nThe pool continues to function after draining.\\n\\n```lua\\nPool:Drain()  -- free memory during a loading screen\\n```","params":[],"returns":[],"function_type":"method","source":{"line":256,"path":"docs/Fluix.lua"}},{"name":"Prewarm","desc":"Immediately allocates `n` objects into the cold pool, bypassing the\\nHeartbeat batch limit. Use this for one-shot forced pre-warming.\\n\\n```lua\\nPool:Prewarm(16)\\n```","params":[{"name":"n","desc":"Number of objects to allocate immediately.","lua_type":"number"}],"returns":[],"function_type":"method","source":{"line":271,"path":"docs/Fluix.lua"}},{"name":"Resize","desc":"Updates the `MinSize` and `MaxSize` limits at runtime. Takes effect on the\\nnext Heartbeat tick.\\n\\n```lua\\nPool:Resize(64, 512)\\n```","params":[{"name":"newMin","desc":"New cold-pool floor.","lua_type":"number"},{"name":"newMax","desc":"New cold-pool ceiling.","lua_type":"number"}],"returns":[],"function_type":"method","source":{"line":287,"path":"docs/Fluix.lua"}},{"name":"Destroy","desc":"Destroys the pool entirely. Disconnects the Heartbeat, clears all state,\\nand marks the pool as destroyed. Calling any method after `Destroy` is a\\nno-op or will error.\\n\\n```lua\\nPool:Destroy()\\n```","params":[],"returns":[],"function_type":"method","source":{"line":301,"path":"docs/Fluix.lua"}},{"name":"GetStats","desc":"Returns a snapshot table of all pool metrics. Useful for dashboards and\\ndebugging.\\n\\n```lua\\nlocal stats = Pool:GetStats()\\nprint(stats.LiveCount, stats.HotSize, stats.PoolSize, stats.MissCount)\\n```","params":[],"returns":[{"desc":"Snapshot of current pool metrics.","lua_type":"PoolerStats"}],"function_type":"method","source":{"line":319,"path":"docs/Fluix.lua"}},{"name":"GetLiveCount","desc":"Returns the number of objects currently out of the pool (acquired but not\\nyet released). Zero-allocation.","params":[],"returns":[{"desc":"","lua_type":"number"}],"function_type":"method","source":{"line":330,"path":"docs/Fluix.lua"}},{"name":"GetPoolSize","desc":"Returns the number of objects currently in the cold pool. Zero-allocation.","params":[],"returns":[{"desc":"","lua_type":"number"}],"function_type":"method","source":{"line":340,"path":"docs/Fluix.lua"}},{"name":"GetHotSize","desc":"Returns the number of objects currently in the hot sub-pool. Zero-allocation.","params":[],"returns":[{"desc":"","lua_type":"number"}],"function_type":"method","source":{"line":350,"path":"docs/Fluix.lua"}},{"name":"GetTotalAvailable","desc":"Returns the total number of objects that can be acquired right now\\n(hot + cold). Zero-allocation.\\n\\n```lua\\nif Pool:GetTotalAvailable() < 4 then\\n    warn(\\"Pool running low\\")\\nend\\n```","params":[],"returns":[{"desc":"","lua_type":"number"}],"function_type":"method","source":{"line":367,"path":"docs/Fluix.lua"}},{"name":"GetDemandEMA","desc":"Returns the smoothed acquisitions-per-window value tracked by the EMA.\\nZero-allocation.","params":[],"returns":[{"desc":"","lua_type":"number"}],"function_type":"method","source":{"line":378,"path":"docs/Fluix.lua"}},{"name":"GetTargetSize","desc":"Returns the current EMA-derived pre-warm target for the cold pool.\\nZero-allocation.","params":[],"returns":[{"desc":"","lua_type":"number"}],"function_type":"method","source":{"line":389,"path":"docs/Fluix.lua"}},{"name":"GetMissCount","desc":"Returns the total number of factory misses since the pool was created.\\nZero-allocation.","params":[],"returns":[{"desc":"","lua_type":"number"}],"function_type":"method","source":{"line":400,"path":"docs/Fluix.lua"}},{"name":"IsOwned","desc":"Returns `true` if `obj` is currently live in this pool (acquired but not\\nyet released).","params":[{"name":"obj","desc":"The object to check.","lua_type":"T"}],"returns":[{"desc":"","lua_type":"boolean"}],"function_type":"method","source":{"line":412,"path":"docs/Fluix.lua"}},{"name":"IsActive","desc":"Returns `true` if the Heartbeat connection is currently live.","params":[],"returns":[{"desc":"","lua_type":"boolean"}],"function_type":"method","source":{"line":422,"path":"docs/Fluix.lua"}},{"name":"IsDestroyed","desc":"Returns `true` if `Destroy` has been called on this pool.","params":[],"returns":[{"desc":"","lua_type":"boolean"}],"function_type":"method","source":{"line":432,"path":"docs/Fluix.lua"}}],"properties":[{"name":"Signals","desc":"Lifecycle signals for this pool. All five are [Signal] connections.\\n\\n| Signal | Parameters | Fires when |\\n|--------|-----------|------------|\\n| `OnAcquire` | `obj: T` | Object left the pool |\\n| `OnRelease` | `obj: T` | Object returned to the pool |\\n| `OnMiss` | `obj: T` | Factory was called (pool was empty) |\\n| `OnGrow` | `added: number, total: number` | Pool expanded |\\n| `OnShrink` | `removed: number, total: number` | Pool contracted |\\n\\n```lua\\nPool.Signals.OnMiss:Connect(function(obj)\\n    warn(\\"Pool miss \u2014 consider raising MinSize or Headroom\\")\\nend)\\n\\nPool.Signals.OnGrow:Connect(function(added, total)\\n    print(\\"Pool grew by\\", added, \\"\u2014 total:\\", total)\\nend)\\n```","lua_type":"PoolerSignals","source":{"line":107,"path":"docs/Fluix.lua"}}],"types":[],"name":"Fluix","desc":"Adaptive, demand-smoothed object pooling for Roblox.\\n\\n\\nFluix is a per-instance generic object pool. It tracks acquisition demand\\nwith an exponential moving average, pre-warms and gradually shrinks the pool\\nto match real usage, and exposes hot/cold priority tiers, cross-pool\\nborrowing, per-object TTL, and lifecycle signals \u2014 all with zero allocations\\non the acquire/release hot path.\\n\\n**Adaptive Sizing.** The Heartbeat pre-warms the cold pool toward\\n`EMA \xd7 Headroom` and gradually shrinks it after `ShrinkGraceSeconds` of\\nsustained surplus. The pool never falls below `MinSize` or rises above\\n`MaxSize`.\\n\\n**Priority Tiers.** When `HotPoolSize > 0`, a hot sub-pool is maintained.\\nAcquire drains hot first, then cold. Release refills hot first, then cold.\\n\\n**Cross-Pool Borrowing.** On a factory miss, Fluix iterates `BorrowPeers`\\nbefore allocating. The borrowed object is tracked as live in the borrowing\\npool and released normally.\\n\\n**Per-Object TTL.** Acquired objects are stamped with a timestamp. The\\nHeartbeat force-reclaims any object held longer than `TTL` seconds.\\n\\n```lua\\nlocal Fluix = require(ReplicatedStorage.Fluix)\\n\\nlocal BulletPool = Fluix.new({\\n    Factory     = function() return Bullet.new() end,\\n    Reset       = function(b) b:Reset() end,\\n    MinSize     = 32,\\n    HotPoolSize = 8,\\n    TTL         = 10,\\n})\\n\\nBulletPool:Seed(20)\\n\\nlocal bullet = BulletPool:Acquire(function(b)\\n    b.Position = spawnPos\\n    b.Velocity = direction * speed\\nend)\\n\\nBulletPool:Release(bullet)\\n```","external_types":[{"name":"Signal","url":"https://vel136.github.io/VeSignal/"}],"source":{"line":54,"path":"docs/Fluix.lua"}}')}}]);